section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/business-model-planning.json",
  "title": "Business Model Planning",
  "type": "object",
  "required": [
    "artefact_id",
    "niches",
    "weights",
    "blue_ocean",
    "vpc",
    "pricing_model",
    "rejection_reasons",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "niches": {
      "type": "array",
      "description": "3-5 niche scorecards",
      "minItems": 1
    },
    "weights": {
      "type": "object",
      "description": "criterion \u2192 weight, must sum to 1.0"
    },
    "blue_ocean": {
      "type": "object",
      "description": "eliminate/reduce/raise/create lists + strategy_canvas"
    },
    "vpc": {
      "type": "object",
      "description": "customer_profile + value_map"
    },
    "pricing_model": {
      "type": "string",
      "description": "freemium|subscription|usage|one-time|tiered|per-seat",
      "minLength": 1
    },
    "rejection_reasons": {
      "type": "object",
      "description": "model \u2192 reason for not choosing"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
